-- AUB graduate data seed migration.
-- Idempotent import for the canonical AUB graduate candidate.

DO $$
DECLARE
    v_university_id BIGINT;
BEGIN

    INSERT INTO university (name, name_ar, acronym, country, city, latitude, longitude, campus_name, campus_type)
    SELECT 'American University of Beirut', NULL, 'AUB', 'Lebanon', 'Beirut', NULL, NULL, NULL, NULL
    WHERE NOT EXISTS (
        SELECT 1 FROM university WHERE name = 'American University of Beirut'
    );

    SELECT id INTO v_university_id
    FROM university
    WHERE name = 'American University of Beirut'
    ORDER BY id
    LIMIT 1;

    -- AUB reuses hub/catalog URLs across multiple graduate programs.
    ALTER TABLE graduate_program DROP CONSTRAINT IF EXISTS uq_graduate_program_university_url;

    INSERT INTO degree_type (code, name)
    VALUES
        ('MASTER', 'Master'),
        ('PHD', 'Doctor of Philosophy'),
        ('DIPLOMA', 'Diploma'),
        ('CERTIFICATE', 'Certificate')
    ON CONFLICT (code) DO UPDATE SET
        name = EXCLUDED.name,
        updated_at = NOW();

    INSERT INTO language (name, code, native_name)
    VALUES ('English', 'en', 'English')
    ON CONFLICT (code) DO UPDATE SET
        name = EXCLUDED.name,
        native_name = EXCLUDED.native_name;

    CREATE TEMP TABLE aub_source_seed (
        source_id TEXT PRIMARY KEY,
        page_title TEXT NOT NULL,
        url TEXT NOT NULL,
        date_accessed DATE
    ) ON COMMIT DROP;

    INSERT INTO aub_source_seed (source_id, page_title, url, date_accessed)
    SELECT source_id, page_title, url, date_accessed
