    );

    INSERT INTO source (university_id, title, url, source_type, accessed_at)
    SELECT v_university_id, page_title, url, 'WEB', date_accessed
    FROM aub_source_seed
    ON CONFLICT (university_id, url) DO UPDATE SET
        title = EXCLUDED.title,
        source_type = EXCLUDED.source_type,
        accessed_at = EXCLUDED.accessed_at,
        updated_at = NOW();

    INSERT INTO university_faculty (university_id, name, short_name, faculty_type, official_url, notes)
    SELECT v_university_id, name, short_name, faculty_type, official_url, notes
    FROM jsonb_to_recordset($AUB$[{"name":"Faculty of Arts and Sciences","short_name":null,"faculty_type":"FACULTY","official_url":"https://www.aub.edu.lb/fas/Pages/default.aspx","notes":null},{"name":"Faculty of Health Sciences","short_name":null,"faculty_type":"FACULTY","official_url":"https://www.aub.edu.lb/fhs/Pages/default.aspx","notes":null},{"name":"Faculty of Medicine","short_name":null,"faculty_type":"FACULTY","official_url":null,"notes":null},{"name":"Maroun Semaan Faculty of Engineering and Architecture","short_name":null,"faculty_type":"FACULTY","official_url":"https://www.aub.edu.lb/msfea/Pages/default.aspx","notes":null},{"name":"Rafic Hariri School of Nursing","short_name":null,"faculty_type":"SCHOOL","official_url":"https://www.aub.edu.lb/hson/Pages/default.aspx","notes":null},{"name":"Suliman S. Olayan School of Business","short_name":null,"faculty_type":"SCHOOL","official_url":"https://www.aub.edu.lb/osb/Pages/default.aspx","notes":null}]$AUB$::jsonb) AS fac(
        name TEXT,
        short_name TEXT,
        faculty_type TEXT,
        official_url TEXT,
        notes TEXT
    )
    ON CONFLICT (university_id, name) DO UPDATE SET
        short_name = EXCLUDED.short_name,
        faculty_type = EXCLUDED.faculty_type,
        official_url = EXCLUDED.official_url,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO university_department (university_id, faculty_id, name, short_name, official_url, notes)
    SELECT
        v_university_id,
        fac.id,
        dep.name,
        dep.short_name,
        dep.official_url,
        dep.notes
    FROM jsonb_to_recordset($AUB$[{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Arabic and Near Eastern Languages","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Biology","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Chemistry","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Computer Science","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Earth Sciences","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Economics","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of English","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of History and Archaeology","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Mathematics","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Philosophy","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Political Studies and Public Administration","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Psychology","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Department of Sociology, Anthropology and Media Studies","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Fine Arts and Art History","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Arts and Sciences","name":"Graduate Program in Computational Science (GPCS)","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Health Sciences","name":"Environmental Health Department","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Health Sciences","name":"Graduate Public Health Program","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Health Sciences","name":"Health Management and Policy Department","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Medicine","name":"Anatomy, Cell Biology and Physiological Sciences","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Medicine","name":"Biochemistry and Molecular Genetics","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Medicine","name":"Doctoral Program in Biomedical Sciences","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Medicine","name":"Experimental Pathology, Immunology and Microbiology","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Faculty of Medicine","name":"Pharmacology and Toxicology","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Baha and Walid Bassatne Department of Chemical Engineering and Advanced Energy","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Biomedical Engineering Program","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Civil and Environmental Engineering","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Electrical and Computer Engineering","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Industrial Engineering and Management","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"Mechanical Engineering","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Maroun Semaan Faculty of Engineering and Architecture","name":"School of Architecture and Design","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Rafic Hariri School of Nursing","name":"Rafic Hariri School of Nursing","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Suliman S. Olayan School of Business","name":"MBA Online","short_name":null,"official_url":null,"notes":null},{"faculty_name":"Suliman S. Olayan School of Business","name":"Specialized Master's","short_name":null,"official_url":null,"notes":null}]$AUB$) AS dep(
