    CREATE TEMP TABLE aub_program_seed (
        id TEXT PRIMARY KEY,
        faculty TEXT NOT NULL,
        department TEXT,
        major_category TEXT,
        major TEXT,
        degree_type TEXT,
        official_degree_name TEXT,
        thesis_or_non_thesis TEXT,
        credits INTEGER,
        duration_value NUMERIC(10, 2),
        duration_unit TEXT,
        duration_raw_text TEXT,
        language TEXT,
        delivery_mode TEXT,
        program_description TEXT,
        admission_requirements TEXT,
        required_documents TEXT,
        gre_requirement TEXT,
        gmat_requirement TEXT,
        english_requirement TEXT,
        portfolio_requirement TEXT,
        interview_requirement TEXT,
        experience_requirement TEXT,
        tuition_academic_year TEXT,
        tuition_currency TEXT,
        tuition_billing_basis TEXT,
        tuition_amount NUMERIC(12, 2),
        tuition_category TEXT,
        tuition_notes TEXT,
        tuition_source_ids JSONB,
        tuition_scope_level TEXT,
        additional_fees JSONB,
        deadlines JSONB,
        scholarships JSONB,
        financial_aid JSONB,
        payment_plans JSONB,
        accreditation TEXT,
        official_program_url TEXT NOT NULL,
        sources JSONB NOT NULL,
        tracks JSONB NOT NULL,
        notes TEXT
    ) ON COMMIT DROP;

    INSERT INTO aub_program_seed (
        id, faculty, department, major_category, major, degree_type, official_degree_name, thesis_or_non_thesis, credits,
        duration_value, duration_unit, duration_raw_text, language, delivery_mode, program_description, admission_requirements,
        required_documents, gre_requirement, gmat_requirement, english_requirement, portfolio_requirement, interview_requirement,
        experience_requirement, tuition_academic_year, tuition_currency, tuition_billing_basis, tuition_amount, tuition_category,
        tuition_notes, tuition_source_ids, tuition_scope_level, additional_fees, deadlines, scholarships, financial_aid,
        payment_plans, accreditation, official_program_url, sources, tracks, notes
    )
    SELECT
        id, faculty, department, major_category, major, degree_type, official_degree_name, thesis_or_non_thesis, credits,
        duration_value, duration_unit, duration_raw_text, language, delivery_mode, program_description, admission_requirements,
        required_documents, gre_requirement, gmat_requirement, english_requirement, portfolio_requirement, interview_requirement,
        experience_requirement, tuition_academic_year, tuition_currency, tuition_billing_basis, tuition_amount, tuition_category,
