hesis\". Original duration text: At least six regular semesters beyond the master's degree"},{"id":"osb-mba-online","faculty":"Suliman S. Olayan School of Business","department":"MBA Online","major_category":"Business","major":"Business Administration","degree_type":"MASTER","official_degree_name":"MBA Online","thesis_or_non_thesis":null,"credits":36,"duration_value":null,"duration_unit":null,"duration_raw_text":"6, 10, or 12 trimesters","language":"English","delivery_mode":"ONLINE","program_description":"Fully online MBA designed for working professionals with eight core courses and four electives.","admission_requirements":"An undergraduate degree is required. GMAT is considered, and relevant work experience is expected.","required_documents":null,"gre_requirement":null,"gmat_requirement":"GMAT score required; the program page says it looks at the quantitative and verbal balance.","english_requirement":"Use AUB graduate English/RUSE requirements.","portfolio_requirement":null,"interview_requirement":null,"experience_requirement":"Work experience is explicitly expected.","tuition_academic_year":"2026-2027","tuition_currency":"USD","tuition_billing_basis":"PER_CREDIT","tuition_amount":619,"tuition_category":"MBA Online","tuition_notes":"Special MBA Online fee confirmed by the OSB Costs and Fees page; official 2026-2027 fee schedule supersedes the older public page value.","tuition_source_ids":["aub_tuition_2026_2027","aub_osb_mba_costs_fees"],"tuition_scope_level":"PROGRAM","additional_fees":null,"deadlines":null,"scholarships":null,"financial_aid":null,"payment_plans":null,"accreditation":null,"official_program_url":"https://www.aub.edu.lb/osb/OMBA/Pages/default.aspx","sources":[{"source_id":"aub_osb_omba","page_title":"MBA Online Suliman S. Olayan School of Business","url":"https://www.aub.edu.lb/osb/OMBA/Pages/default.aspx","date_accessed":"2026-06-25"},{"source_id":"aub_osb_omba_program","page_title":"The Program MBA Online","url":"https://www.aub.edu.lb/osb/OMBA/Pages/program.aspx","date_accessed":"2026-06-25"},{"source_id":"aub_osb_omba_admissions","page_title":"Admissions and Fees MBA Online","url":"https://www.aub.edu.lb/osb/OMBA/Pages/Admission.aspx","date_accessed":"2026-06-25"},{"source_id":"aub_english_requirements","page_title":"Check your English Language Requirements","url":"https://www.aub.edu.lb/admissions/Pages/EnglishRequirements.aspx","date_accessed":"2026-06-25"}],"tracks":["Optional concentration tracks"],"notes":"Original duration text: 6, 10, or 12 trimesters"},{"id":"osb-mfin","faculty":"Suliman S. Olayan School of Business","department":"Specialized Master's","major_category":"Business","major":"Finance","degree_type":"MASTER","official_degree_name":"Master's in Finance","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"duration_raw_text":null,"language":"English","delivery_mode":null,"program_description":"Finance master's program focused on financial markets, valuation, and analytical skills.","admission_requirements":null,"required_documents":null,"gre_requirement":null,"gmat_requirement":null,"english_requirement":"Use AUB graduate English/RUSE requirements.","portfolio_requirement":null,"interview_requirement":null,"experience_requirement":null,"tuition_academic_year":"2026-2027","tuition_currency":"USD","tuition_billing_basis":"PER_CREDIT","tuition_amount":1244,"tuition_category":"Suliman S. Olayan School of Business Graduate Tuition","tuition_notes":"Official AUB Tuition & Fees 2026-2027 schedule.","tuition_source_ids":["aub_tuition_2026_2027"],"tuition_scope_level":"FACULTY","additional_fees":null,"deadlines":null,"scholarships":null,"financial_aid":null,"payment_plans":null,"accreditation":null,"official_program_url":"https://www.aub.edu.lb/osb/MFIN/Pages/default.aspx","sources":[{"source_id":"aub_osb_mfin","page_title":"Master's in Finance Leading the future of finance","url":"https://www.aub.edu.lb/osb/MFIN/Pages/default.aspx","date_accessed":"2026-06-25"}],"tracks":[],"notes":null},{"id":"osb-mhrm","faculty":"Suliman S. Olayan School of Business","department":"Specialized Master's","major_category":"Business","major":"Human Resource Management","degree_type":"MASTER","official_degree_name":"Master's in Human Resource Management","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"duration_raw_text":null,"language":"English","delivery_mode":null,"program_description":"Specialized master's program for aspiring HRM practitioners and early-career professionals.","admission_requirements":"Undergraduate degree from AUB or another recognized university in business, social science, health/science, humanities, or a related field.","required_documents":null,"gre_requirement":null,"gmat_requirement":null,"english_requirement":"Use AUB graduate English/RUSE requirements.","portfolio_requirement":null,"interview_requirement":null,"experience_requirement":"Early-career practitioners are explicitly welcomed.","tuition_academic_year":"2026-2027","tuition_currency":"USD","tuition_billing_basis":"PER_CREDIT","tuition_amount":1244,"tuition_category":"Suliman S. Olayan School of Business Graduate Tuition","tuition_notes":"Official AUB Tuition & Fees 2026-2027 schedule.","tuition_source_ids":["aub_tuition_2026_2027"],"tuition_scope_level":"FACULTY","additional_fees":null,"deadlines":null,"scholarships":null,"financial_aid":null,"payment_plans":null,"accreditation":null,"official_program_url":"https://www.aub.edu.lb/osb/MHRM/Pages/default.aspx","sources":[{"source_id":"aub_osb_mhrm","page_title":"Master's in Human Resource Management Developing and managing leaders of the future","url":"https://www.aub.edu.lb/osb/MHRM/Pages/default.aspx","date_accessed":"2026-06-25"}],"tracks":[],"notes":null},{"id":"osb-msba","faculty":"Suliman S. Olayan School of Business","department":"Specialized Master's","major_category":"Business","major":"Business Analytics","degree_type":"MASTER","official_degree_name":"Master's of Science in Business Analytics","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"duration_raw_text":null,"language":"English","delivery_mode":null,"program_description":"Business analytics master's program focused on big data, modeling, visualization, and business decision-making.","admission_requirements":null,"required_documents":null,"gre_requirement":null,"gmat_requirement":null,"english_requirement":"Use AUB graduate English/RUSE requirements.","portfolio_requirement":null,"interview_requirement":null,"experience_requirement":null,"tuition_academic_year":"2026-2027","tuition_currency":"USD","tuition_billing_basis":"PER_CREDIT","tuition_amount":1244,"tuition_category":"Suliman S. Olayan School of Business Graduate Tuition","tuition_notes":"Official AUB Tuition & Fees 2026-2027 schedule.","tuition_source_ids":["aub_tuition_2026_2027"],"tuition_scope_level":"FACULTY","additional_fees":null,"deadlines":null,"scholarships":null,"financial_aid":null,"payment_plans":null,"accreditation":null,"official_program_url":"https://www.aub.edu.lb/osb/MSBA/Pages/default.aspx","sources":[{"source_id":"aub_osb_msba","page_title":"MSBA, the leading Business Analytics program in the MENA region Where business and big data meet","url":"https://www.aub.edu.lb/osb/MSBA/Pages/default.aspx","date_accessed":"2026-06-25"}],"tracks":[],"notes":null}]$AUB$) AS seed(
        id TEXT,
        faculty TEXT,
        department TEXT,
        major_category TEXT,
        major TEXT,
        degree_type TEXT,
        official_degree_name TEXT,
        thesis_or_non_thesis TEXT,
        credits INTEGER,
        duration_value NUMERIC(10, 2),
        duration_unit TEXT,
        duration_raw_text TEXT,
        language TEXT,
        delivery_mode TEXT,
        program_description TEXT,
        admission_requirements TEXT,
        required_documents TEXT,
        gre_requirement TEXT,
        gmat_requirement TEXT,
        english_requirement TEXT,
        portfolio_requirement TEXT,
        interview_requirement TEXT,
        experience_requirement TEXT,
        tuition_academic_year TEXT,
        tuition_currency TEXT,
        tuition_billing_basis TEXT,
        tuition_amount NUMERIC(12, 2),
        tuition_category TEXT,
        tuition_notes TEXT,
        tuition_source_ids JSONB,
        tuition_scope_level TEXT,
        additional_fees JSONB,
        deadlines JSONB,
        scholarships JSONB,
        financial_aid JSONB,
        payment_plans JSONB,
        accreditation TEXT,
        official_program_url TEXT,
        sources JSONB,
        tracks JSONB,
        notes TEXT
    );

    INSERT INTO graduate_program (
        university_id, faculty_id, department_id, degree_type_id, program_key,
        major_category, major, official_degree_name, thesis_or_non_thesis,
        credits, duration_value, duration_unit, primary_language_id, delivery_mode,
        program_description, official_program_url, source_id, notes
    )
    SELECT
        v_university_id,
        fac.id,
        dep.id,
        dt.id,
        seed.id,
        seed.major_category,
        seed.major,
        seed.official_degree_name,
        seed.thesis_or_non_thesis,
        seed.credits,
        seed.duration_value,
        seed.duration_unit,
        lang.id,
        seed.delivery_mode,
        seed.program_description,
        seed.official_program_url,
        (SELECT s.id FROM jsonb_array_elements(seed.sources) WITH ORDINALITY AS src(src_obj, ord)
         JOIN aub_source_seed ss ON ss.source_id = (src.src_obj->>'source_id')
         JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
         ORDER BY src.ord LIMIT 1),
        concat_ws(' ', NULLIF(seed.notes, ''), CASE WHEN seed.duration_raw_text IS NOT NULL THEN 'Original duration text: ' || seed.duration_raw_text END)
    FROM aub_program_seed seed
    JOIN university_faculty fac
      ON fac.university_id = v_university_id
     AND fac.name = seed.faculty
    LEFT JOIN university_department dep
      ON dep.university_id = v_university_id
     AND dep.faculty_id = fac.id
     AND dep.name = seed.department
    LEFT JOIN degree_type dt
      ON dt.code = seed.degree_type
    LEFT JOIN language lang
      ON lang.name = seed.language
    ON CONFLICT (university_id, program_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        degree_type_id = EXCLUDED.degree_type_id,
        major_category = EXCLUDED.major_category,
        major = EXCLUDED.major,
        official_degree_name = EXCLUDED.official_degree_name,
        thesis_or_non_thesis = EXCLUDED.thesis_or_non_thesis,
        credits = EXCLUDED.credits,
        duration_value = EXCLUDED.duration_value,
        duration_unit = EXCLUDED.duration_unit,
        primary_language_id = EXCLUDED.primary_language_id,
        delivery_mode = EXCLUDED.delivery_mode,
        program_description = EXCLUDED.program_description,
        official_program_url = EXCLUDED.official_program_url,
        source_id = EXCLUDED.source_id,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO graduate_program_alias (university_id, program_id, alias_type, alias, source_id, note)
    SELECT
        v_university_id,
        gp.id,
        'OLD_ID',
        'fas-gpcs',
        gp.source_id,
        'Old duplicate ID for the canonical Computational Science record.'
    FROM graduate_program gp
    WHERE gp.university_id = v_university_id
      AND gp.program_key = 'fas-gpcs-ms'
    ON CONFLICT (university_id, alias_type, alias) DO UPDATE SET
        program_id = EXCLUDED.program_id,
        source_id = EXCLUDED.source_id,
        note = EXCLUDED.note,
        updated_at = NOW();

    INSERT INTO graduate_program_track (university_id, program_id, track_type, track_name, track_order, is_primary, description, source_id, notes)
    SELECT
        v_university_id,
        gp.id,
        'TRACK',
        track_vals.track_name,
        track_vals.ord,
        track_vals.ord = 1,
        NULL,
        gp.source_id,
        'Imported from concentrations_or_tracks.'
    FROM aub_program_seed seed
    JOIN graduate_program gp
      ON gp.university_id = v_university_id
     AND gp.program_key = seed.id
    JOIN LATERAL jsonb_array_elements_text(COALESCE(seed.tracks, '[]'::jsonb)) WITH ORDINALITY AS track_vals(track_name, ord)
      ON TRUE
    ON CONFLICT (program_id, track_type, track_name) DO UPDATE SET
        track_order = EXCLUDED.track_order,
        is_primary = EXCLUDED.is_primary,
        source_id = EXCLUDED.source_id,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO graduate_tuition_rate (
        university_id, faculty_id, department_id, program_id, scope_level, record_key,
        academic_year, currency, billing_basis, amount, category, notes, source_id
    )
    SELECT
        v_university_id,
        gp.faculty_id,
        gp.department_id,
        gp.id,
        seed.tuition_scope_level,
        seed.id || ':tuition:' || seed.tuition_academic_year,
        seed.tuition_academic_year,
        seed.tuition_currency,
        seed.tuition_billing_basis,
        seed.tuition_amount,
        seed.tuition_category,
        seed.tuition_notes,
        tuition_src.id
    FROM aub_program_seed seed
    JOIN graduate_program gp
      ON gp.university_id = v_university_id
     AND gp.program_key = seed.id
    LEFT JOIN LATERAL (
        SELECT s.id
        FROM jsonb_array_elements_text(seed.tuition_source_ids) WITH ORDINALITY AS ts(source_seed_id, ord)
        JOIN aub_source_seed ss ON ss.source_id = ts.source_seed_id
        JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
        ORDER BY ts.ord
        LIMIT 1
    ) tuition_src ON TRUE
    WHERE seed.tuition_academic_year IS NOT NULL
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        program_id = EXCLUDED.program_id,
        scope_level = EXCLUDED.scope_level,
        academic_year = EXCLUDED.academic_year,
        currency = EXCLUDED.currency,
        billing_basis = EXCLUDED.billing_basis,
        amount = EXCLUDED.amount,
        category = EXCLUDED.category,
        notes = EXCLUDED.notes,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();

    INSERT INTO graduate_admission_requirement (
        university_id, faculty_id, department_id, program_id, scope_level, record_key,
        requirement_type, requirement_text, comparison_operator, threshold_value, threshold_unit, is_required, notes, source_id
    )
    SELECT * FROM (
        SELECT
            v_university_id,
            gp.faculty_id,
            gp.department_id,
            gp.id,
            'PROGRAM'::TEXT,
            seed.id || ':admission_requirements',
            'GENERAL'::TEXT,
            seed.admission_requirements,
            NULL::TEXT,
            NULL::NUMERIC,
            NULL::TEXT,
            TRUE,
            NULL::TEXT,
            gp.source_id
        FROM aub_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.admission_requirements IS NOT NULL
        UNION ALL
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM', seed.id || ':gre_requirement', 'GRE', seed.gre_requirement,
            NULL, NULL, NULL, NOT (seed.gre_requirement ILIKE '%no gre%'), NULL, gp.source_id
        FROM aub_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.gre_requirement IS NOT NULL
        UNION ALL
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM', seed.id || ':gmat_requirement', 'GMAT', seed.gmat_requirement,
            NULL, NULL, NULL, TRUE, NULL, gp.source_id
        FROM aub_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.gmat_requirement IS NOT NULL
        UNION ALL
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM', seed.id || ':english_requirement', 'ENGLISH', seed.english_requirement,
            NULL, NULL, NULL, TRUE, NULL, gp.source_id
        FROM aub_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.english_requirement IS NOT NULL
        UNION ALL
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM', seed.id || ':experience_requirement', 'EXPERIENCE', seed.experience_requirement,
            NULL, NULL, NULL, TRUE, NULL, gp.source_id
        FROM aub_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.experience_requirement IS NOT NULL
    ) req
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        program_id = EXCLUDED.program_id,
        scope_level = EXCLUDED.scope_level,
        requirement_type = EXCLUDED.requirement_type,
        requirement_text = EXCLUDED.requirement_text,
        is_required = EXCLUDED.is_required,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();

    INSERT INTO graduate_accreditation (
        university_id, faculty_id, department_id, program_id, scope_level, record_key,
        name, authority, status, valid_from, valid_until, notes, source_id
    )
    SELECT
        v_university_id,
        gp.faculty_id,
        gp.department_id,
        gp.id,
        'PROGRAM',
        seed.id || ':accreditation',
        seed.accreditation,
        CASE WHEN seed.accreditation ILIKE '%CEPH%' THEN 'CEPH' ELSE NULL END,
        NULL,
        NULL,
        NULL,
        seed.accreditation,
        gp.source_id
    FROM aub_program_seed seed
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
    WHERE seed.accreditation IS NOT NULL
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        program_id = EXCLUDED.program_id,
        scope_level = EXCLUDED.scope_level,
        name = EXCLUDED.name,
        authority = EXCLUDED.authority,
        status = EXCLUDED.status,
        notes = EXCLUDED.notes,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();

    INSERT INTO graduate_program_source (
        university_id, program_id, source_id, source_role, source_order, evidence_text, notes
    )
    SELECT
        v_university_id,
        gp.id,
        s.id,
        CASE WHEN src_order = 1 THEN 'PRIMARY' ELSE 'SECONDARY' END,
        src_order,
        src_obj->>'page_title',
        NULL
    FROM aub_program_seed seed
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
    JOIN LATERAL jsonb_array_elements(seed.sources) WITH ORDINALITY AS src(src_obj, src_order) ON TRUE
    JOIN aub_source_seed ss ON ss.source_id = (src.src_obj->>'source_id')
    JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
    ON CONFLICT (program_id, source_id, source_role) DO UPDATE SET
        source_order = EXCLUDED.source_order,
        evidence_text = EXCLUDED.evidence_text,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO graduate_program_source (
        university_id, program_id, source_id, source_role, source_order, evidence_text, notes
    )
    SELECT
        v_university_id,
        gp.id,
        s.id,
        'TUITION',
        ts.ord,
        'Tuition source',
        NULL
    FROM aub_program_seed seed
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
    JOIN LATERAL jsonb_array_elements_text(COALESCE(seed.tuition_source_ids, '[]'::jsonb)) WITH ORDINALITY AS ts(source_seed_id, ord) ON TRUE
    JOIN aub_source_seed ss ON ss.source_id = ts.source_seed_id
    JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
    ON CONFLICT (program_id, source_id, source_role) DO NOTHING;

END $$;
